B.U7=s(["4 Douglasie-Rahmenh\xf6lzer 90\xd790 (3 m) je auf 2,8 m abl\xe4ngen \u2013 4 durchgehende Bretter f\xfcr 2 Balken (Restst\xfcck 20 cm).","Je Balkenseite 2 Bretter deckungsgleich aufeinanderlegen (untere + obere Lage).","Kontaktfl\xe4chen vollfl\xe4chig mit D4-Leim bestreichen.","Beide Lagen alle ~20 cm mit 8\xd7100-Schrauben (versetzt) verschrauben.","Ergebnis: 2 durchgehende Doppelbalken \xe0 2,8 m \u2013 ohne Stoss."],t.s)
B.UT=s(["assets/bau/01_doppelbalken.png"],t.s)
B.Iz=new A.ib("doppelbalken","Doppelbalken bauen",B.U7,"Bretter gerade und b\xfcndig verleimt; keine St\xf6sse.","Durchgehende Bretter = maximale Steifigkeit. Die zwei verleimten Lagen wirken zugleich gegen Verzug \u2013 D4-Leim (wasserfest) vollfl\xe4chig auftragen.",B.UT)
B.SU=s(["Fester, sonniger, windgesch\xfctzter Platz; Flugl\xf6cher sp\xe4ter nach S\xfcdost, Flugbahn 2\u20133 m frei, hinten 80\u2013100 cm Arbeitsraum.","Rechteck 2000 \xd7 400 mm anzeichnen: Beinabstand l\xe4ngs 2000 mm, Balkenachse (vorn/hinten) 400 mm.","Beine ~400 mm von den Enden einr\xfccken.","Rechtwinkligkeit mit einer Latten-Lehre und gleichen Diagonalen pr\xfcfen."],t.s)
B.VV=s(["assets/bau/02_draufsicht_rechteck.png"],t.s)
B.IE=new A.ib("rechteck","Standort & Rechteck anzeichnen",B.SU,"Beinabstand 2000 mm, Achse 400 mm, Diagonalen gleich.",null,B.VV)
B.UZ=s(["4\xd7 Krinner U-FIX 91 an den angezeichneten Punkten ansetzen.","Mit einem Stahlstab durch die Aufnahme lotrecht eindrehen.","Mit der Wasserwaage an der H\xfclse laufend die Senkrechte kontrollieren.","Die 4 Aufnahmen grob auf gleiche H\xf6he bringen (Feinausgleich folgt \xfcber die Bolzen)."],t.s)
B.TV=s(["assets/bau/03_erdschraube_lot.png"],t.s)
B.Iy=new A.ib("erdschrauben","Erdschrauben eindrehen",B.UZ,"Jede Erdschraube lotrecht; Positionen = angezeichnetes Rechteck.","Auf Steine/Wurzeln achten \u2013 notfalls Schraube leicht versetzen, das Rechteck aber halten.",B.TV)
B.V_=s(["4 Pfosten aus Douglasie 90\xd790 auf ~120 mm zuschneiden.","Je Pfosten in eine U-FIX-Aufnahme stellen.","Seitlich mit 8\xd7100-Schraube durchbolzen."],t.s)
B.Te=s(["assets/bau/04_pfosten_ufix.png"],t.s)
B.Iu=new A.ib("pfosten","Pfosten setzen",B.V_,"Pfosten fest, grob gleiche Oberkante.",null,B.Te)
B.TO=s(["In jeden Pfostenkopf mittig 16 mm bohren (Forstner-/Holzbohrer).","Einschlagmutter M16 b\xfcndig einsetzen.","Sechskantschraube M16\xd7100 eindrehen, grosse Auflagescheibe auflegen.","Kontermutter aufsetzen, aber noch NICHT kontern (Feinjustage folgt beim Nivellieren)."],t.s)
B.uO=s(["assets/bau/05_nivellierbolzen.png"],t.s)
B.Iv=new A.ib("nivellierbolzen","Nivellier-Bolzen einbauen",B.TO,"Schraube leichtg\xe4ngig, Scheibe plan, Verstellweg \xb125 mm frei.",null,B.uO)
B.Wq=s(["Die 2 Doppelbalken auf die 4 Auflagescheiben legen (Achse 400 mm).","Mit Kreuzlinienlaser oder Schlauchwaage die 4 Bolzen in EINE Ebene drehen \u2013 in L\xe4ngs- UND Querrichtung waagerecht.","Kontermuttern fest anziehen.","Jeden Balken mit 2 Schwerlast-Winkeln (90\xd790\xd765) auf den Pfosten sichern (8 Winkel gesamt)."],t.s)
B.Sa=s(["assets/bau/06_querschnitt_aufbau.png","assets/bau/05_nivellierbolzen.png"],t.s)
B.Ix=new A.ib("nivellieren","Balken auflegen & nivellieren",B.Wq,"Balken-Oberkante waagerecht l\xe4ngs UND quer; Kontermuttern fest.","Schl\xfcsselschritt \u2013 hier entsteht die ebene, r\xfcckenschonende H\xf6he. Ruhig mehrfach nachmessen.",B.Sa)
B.Tb=s(["4 Platten 560 \xd7 500 mm aus der Schaltafel zuschneiden (falls nicht im Markt geschnitten).","Alle Schnittkanten SOFORT versiegeln (Hirnholz zuerst) \u2013 gr\xf6sster Langlebigkeits-Faktor.","Je Platte 2\u20134 Entw\xe4sserungsl\xf6cher \xd8 8 mm bohren."],t.s)
B.Tt=s(["assets/bau/07_platte_entwaesserung.png"],t.s)
B.ID=new A.ib("platten_zuschnitt","Platten zuschneiden & versiegeln",B.Tb,"Kanten rundum versiegelt; L\xf6cher gebohrt.",null,B.Tt)
B.TB=s(["Je Platte mittig \xfcber beide Balken legen (fasst die Waage 500\xd7430 mit Rand).","Von oben mit Terrassenschraube A2 5\xd750 verschrauben (steift den Stand aus).","Jede Platte mit der Wasserwaage pr\xfcfen."],t.s)
B.Wk=s(["assets/bau/08_platte_auf_balken.png"],t.s)
B.IA=new A.ib("platten_montage","Platten aufschrauben",B.TB,"Jede Platte waagerecht (wichtig f\xfcr Waagengenauigkeit); V\xf6lkerabstand \u2248 265 mm, Plattenl\xfccke ~160 mm.",null,B.Wk)
B.UU=s(["Ganzen Stand mit Holz\xf6l/UV-Lasur behandeln, v. a. Hirnholz und Schnittkanten.","Trocknungszeit laut Hersteller einhalten."],t.s)
B.uQ=s(["assets/bau/10_seitenansicht_gesamt.png"],t.s)
B.IB=new A.ib("oel","\xd6len & lasieren",B.UU,"Kein blankes Hirnholz mehr; alle Fl\xe4chen behandelt.","Unbehandeltes Douglasie ist bienenfreundlich \u2013 nur aussen/Kanten sch\xfctzen, keine Biozide an der Beute.",B.uQ)
B.Uk=s(["HiveWatch-Waage je Platte LOSE auflegen \u2013 nichts seitlich \xfcberbr\xfccken (keine Steine/Leisten).","3-m-Kabel in einer Kantennut am Pfosten herabf\xfchren, Logger gesch\xfctzt platzieren.","Waagen tarieren.","Beuten aufsetzen (Reihenfolge Platte \u2192 Waage \u2192 Beute), Flugrichtung S\xfcdost pr\xfcfen, kalibrieren."],t.s)
B.T_=s(["assets/bau/09_waagenstapel.png"],t.s)
B.IF=new A.ib("waagen_beuten","Waagen & Beuten aufsetzen",B.Uk,"Beutenboden \u2248 44 cm; Waage frei (nichts \xfcberbr\xfcckt).",null,B.T_)
B.Vv=s(["Alle Balken waagerecht, Kontermuttern fest.","Alle 8 Schwerlast-Winkel montiert.","Alle 4 Platten waagerecht & verschraubt, Entw\xe4sserungsl\xf6cher offen.","Alle Schnittkanten/Hirnholz versiegelt und behandelt.","Flugl\xf6cher S\xfcdost, Flugbahn frei, hinten 80\u2013100 cm Arbeitsraum."],t.s)
B.Iw=new A.ib("endabnahme","Endabnahme",B.Vv,"Keine Durchbiegung sichtbar (< 0,5 mm bei Vollvolk).",null,B.uQ)
B.Ts=s(["Nach 2\u20134 Wochen die Setzung pr\xfcfen.","Mit den 4 Bolzen nachnivellieren (Laser/Wasserwaage).","Alle Schrauben nachziehen (Winkel, Platten, Doppelbalken)."],t.s)
B.IC=new A.ib("nachkontrolle","Nachkontrolle (nach 2\u20134 Wochen)",B.Ts,"Wieder exakt waagerecht; keine losen Verbindungen.",null,B.uO)
